40	
41	function fmtMm(value: number | null | undefined): string {
42	  if (value == null || !Number.isFinite(value)) return '—';
43	  if (Math.abs(value) >= 1000) return `${(value / 1000).toFixed(2)} m`;
44	  return `${value.toFixed(0)} mm`;
45	}
46	
47	export function InspectorPropertiesFor(
48	  el: Element,
49	  t: TFunction,
50	  options?: {
51	    elementsById?: Record<string, Element>;
52	    onPropertyChange?: (property: string, value: unknown) => void;
53	  },
54	): JSX.Element {
55	  const f = (key: string) => t(`inspector.fields.${key}`);
