61	      );
62	      return (
63	        <div className="flex flex-col gap-2">
64	          <FieldRow label={f('thickness')} value={fmtMm(el.thicknessMm)} />
65	          <FieldRow label={f('height')} value={fmtMm(el.heightMm)} />
66	          <FieldRow label={f('level')} value={el.levelId} mono />
67	
68	          <div className="flex items-center gap-2 py-0.5">
69	            <span className="text-xs text-muted w-28 shrink-0">{f('roofAttachment')}</span>
70	            <select
71	              className="flex-1 text-xs bg-surface border border-border rounded px-1 py-0.5"
72	              value={el.roofAttachmentId ?? ''}
73	              onChange={(e2) => onPropertyChange?.('roofAttachmentId', e2.target.value || null)}
74	            >
75	              <option value="">— None —</option>
76	              {roofs.map((r) => (
77	                <option key={r.id} value={r.id}>
78	                  {r.name ?? r.id}
79	                </option>
80	              ))}
81	            </select>
82	          </div>
83	
84	          <div className="flex items-center gap-2 py-0.5">
85	            <span className="text-xs text-muted w-28 shrink-0">{f('curtainWall')}</span>
86	            <input
87	              type="checkbox"
88	              checked={el.isCurtainWall ?? false}
89	              onChange={(e2) => onPropertyChange?.('isCurtainWall', e2.target.checked)}
90	              className="accent-primary"
91	            />
92	          </div>
93	
94	          {el.isCurtainWall && (
95	            <>
96	              <div className="flex items-center gap-2 py-0.5">
97	                <span className="text-xs text-muted w-28 shrink-0">{f('cwVCount')}</span>
98	                <input
99	                  type="number"
100	                  min={1}
101	                  max={50}
102	                  className="w-16 text-xs bg-surface border border-border rounded px-1 py-0.5"
103	                  value={el.curtainWallVCount ?? ''}
104	                  placeholder="auto"
105	                  onChange={(e2) =>
106	                    onPropertyChange?.(
107	                      'curtainWallVCount',
108	                      e2.target.value === '' ? null : Number(e2.target.value),
109	                    )
110	                  }
111	                />
112	              </div>
113	              <div className="flex items-center gap-2 py-0.5">
114	                <span className="text-xs text-muted w-28 shrink-0">{f('cwHCount')}</span>
115	                <input
116	                  type="number"
117	                  min={1}
118	                  max={50}
119	                  className="w-16 text-xs bg-surface border border-border rounded px-1 py-0.5"
120	                  value={el.curtainWallHCount ?? ''}
121	                  placeholder="auto"
