165	          <FieldRow label={f('family')} value={el.familyTypeId ?? 'Generic 1200 × 1500'} mono />
166	          <FieldRow label={f('width')} value={fmtMm(el.widthMm)} />
167	          <FieldRow label={f('height')} value={fmtMm(el.heightMm)} />
168	          <FieldRow label={f('sillHeight')} value={fmtMm(el.sillHeightMm)} />
169	          <FieldRow label={f('wall')} value={el.wallId} mono />
170	        </div>
171	      );
172	    case 'floor': {
173	      const { elementsById: floorElementsById = {}, onPropertyChange: floorOnPropertyChange } =
174	        options ?? {};
175	      return (
176	        <div className="flex flex-col gap-2">
177	          <FieldRow label={f('thickness')} value={fmtMm(el.thicknessMm)} />
