182	
183	          <div className="flex items-center gap-2 py-0.5">
184	            <span className="text-xs text-muted w-28 shrink-0">{f('floorType')}</span>
185	            <select
186	              className="flex-1 text-xs bg-surface border border-border rounded px-1 py-0.5"
187	              value={el.floorTypeId ?? ''}
188	              onChange={(e2) => floorOnPropertyChange?.('floorTypeId', e2.target.value || null)}
189	            >
190	              <option value="">— None —</option>
191	              {Object.values(floorElementsById)
192	                .filter(
193	                  (e): e is Extract<Element, { kind: 'floor_type' }> => e.kind === 'floor_type',
194	                )
195	                .map((t) => (
196	                  <option key={t.id} value={t.id}>
