198	                  </option>
199	                ))}
200	            </select>
201	          </div>
202	        </div>
203	      );
204	    }
205	    case 'roof': {
206	      const { elementsById: roofElementsById = {}, onPropertyChange: roofOnPropertyChange } =
207	        options ?? {};
208	      return (
209	        <div className="flex flex-col gap-2">
210	          <FieldRow label={f('slope')} value={`${(el.slopeDeg ?? 0).toFixed(1)}°`} />
211	          <FieldRow label={f('overhang')} value={fmtMm(el.overhangMm)} />
212	          <FieldRow label={f('referenceLevel')} value={el.referenceLevelId} mono />
213	          <FieldRow label={f('footprintPoints')} value={String(el.footprintMm.length)} />
214	
215	          <div className="flex items-center gap-2 py-0.5">
216	            <span className="text-xs text-muted w-28 shrink-0">{f('roofType')}</span>
217	            <select
218	              className="flex-1 text-xs bg-surface border border-border rounded px-1 py-0.5"
219	              value={el.roofTypeId ?? ''}
220	              onChange={(e2) => roofOnPropertyChange?.('roofTypeId', e2.target.value || null)}
221	            >
222	              <option value="">— None —</option>
223	              {Object.values(roofElementsById)
