708	function CustomTypeForm({
709	  discipline,
710	  onSave,
711	  onCancel,
712	}: {
713	  discipline: 'door' | 'window';
714	  onSave: (baseFamilyId: string, name: string, params: Record<string, unknown>) => void;
715	  onCancel: () => void;
716	}): JSX.Element {
717	  const families = BUILT_IN_FAMILIES.filter((f) => f.discipline === discipline);
718	  const [baseFamilyId, setBaseFamilyId] = useState(families[0]?.id ?? '');
719	  const [name, setName] = useState('');
720	  const [paramDraft, setParamDraft] = useState<Record<string, string>>({});
721	
722	  const baseFam = getFamilyById(baseFamilyId);
723	  const lengthParams = baseFam?.params.filter((p) => p.type === 'length_mm') ?? [];
724	
725	  function handleSave(): void {
726	    const params: Record<string, unknown> = { name: name.trim(), baseFamilyId };
727	    for (const p of lengthParams) {
728	      const raw = paramDraft[p.key];
729	      const val = raw !== undefined ? Number(raw) : (p.default as number);
730	      if (Number.isFinite(val)) params[p.key] = val;
731	    }
732	    onSave(baseFamilyId, name.trim(), params);
733	  }
734	
735	  return (
736	    <div className="mt-1 space-y-1.5 rounded border border-border bg-background p-2">
737	      <label className={LABEL_CLS}>
738	        Base family
739	        <select
740	          className={INPUT_CLS}
741	          value={baseFamilyId}
742	          onChange={(e) => {
743	            setBaseFamilyId(e.target.value);
744	            setParamDraft({});
745	          }}
746	        >
747	          {families.map((f) => (
748	            <option key={f.id} value={f.id}>
749	              {f.name}
750	            </option>
751	          ))}
752	        </select>
753	      </label>
754	      <label className={LABEL_CLS}>
755	        Type name
756	        <input
757	          className={INPUT_CLS}
758	          value={name}
759	          onChange={(e) => setName(e.target.value)}
760	          placeholder="e.g. Wide fire door"
761	          autoFocus
762	        />
763	      </label>
764	      {lengthParams.map((p) => (
765	        <label key={p.key} className={LABEL_CLS}>
766	          {p.label} (mm)
767	          <input
768	            className={INPUT_CLS}
769	            type="number"
770	            value={paramDraft[p.key] ?? String(p.default as number)}
771	            onChange={(e) => setParamDraft((d) => ({ ...d, [p.key]: e.target.value }))}
772	          />
773	        </label>
774	      ))}
775	      <div className="flex gap-2 pt-0.5">
776	        <button
777	          type="button"
778	          disabled={!name.trim()}
779	          onClick={handleSave}
780	          className="flex-1 rounded border border-border bg-surface-strong px-2 py-0.5 text-[10px] hover:bg-accent-soft disabled:opacity-40"
781	        >
782	          Save type
783	        </button>
784	        <button
785	          type="button"
786	          onClick={onCancel}
787	          className="rounded border border-border px-2 py-0.5 text-[10px] hover:bg-surface-strong"
788	        >
789	          Cancel
790	        </button>
791	      </div>
792	    </div>
793	  );
794	}
